    def step1_bm(self, MainWindow):
        self.calculation_tyoe = "bm"

        if self.checkBox_bm.isChecked():
            try:

                df['Max Von-Mises Stress'] = float(self.sigma_vm.text())
                df['X_normal Stress'] = float(self.sigma_x.text())
                df['Y_normal Stress'] = float(self.sigma_y.text())
                df['Z_normal Stress'] = float(self.sigma_z.text())

                df['Hydrostatic Stress Sigma_h'] = 1/3*(df['X_normal Stress']+df['Y_normal Stress']+df['Z_normal Stress'])
                df['Degree of Multiaxiality'] = df['Hydrostatic Stress Sigma_h']/df['Max Von-Mises Stress']



                variable = ['σvm', 'σx', 'σy', 'σz', 'σh', 'h']
                Description = ['Max Von-Mises Stress', 'X Normal Stress', 'Y Normal Stress', 'Z Normal Stress',
                               'Hydrostatic Stress', 'Degree of Multiaxiality']
                ref = ['calculation', 'calculation', 'calculation', 'calculation', '(3.1.11)', '(3.1.10)']
                value = [float(self.sigma_vm.text()), float(self.sigma_x.text()), float(self.sigma_y.text()),
                         float(self.sigma_z.text()), df['Hydrostatic Stress Sigma_h'], df['Degree of Multiaxiality']]

                self.updatetable(self.tableWidget, 25, variable, Description, value, ref)
                #self.tableWidget.update()

                self.data1['Variable'] = variable
                self.data1['Description'] = Description
                self.data1['Value'] = value
                self.data1['Reference'] = ref


            except Exception as e:
                print (e)

    def step1_w(self, MainWindow):
        if self.checkBox_w.isChecked():
            self.calculation_tyoe="weld"
            try:
                df['sigma_perpendicular'] = float(self.sigma_n.text())
                df['t_l'] = float(self.t_l.text())
                df['Max Von-Mises Stress at welds'] = math.sqrt(float(self.sigma_n.text()) ** 2 + 3 * float(self.t_l.text()) ** 2)
                variable = ['σn', 't_l', 'σvm_w']
                Description = ['Normal Stress Perpendicular to Welds', 'Shear Stress Parallel to Welds', 'Equivalent Stress at Welds']
                value = [df['sigma_perpendicular'], df['t_l'], df['Max Von-Mises Stress at welds']]
                ref = ['calculation', 'calculation', '3.1.14 (modified by STD191010)']

                self.updatetable(self.tableWidget, 25, variable, Description, value, ref)

                self.data1_w['Variable'] = variable
                self.data1_w['Description'] = Description
                self.data1_w['Value'] = value
                self.data1_w['Reference'] = ref

            except Exception as e:
                print (e)

