    def updatetable(self, table, total_rows, variable, Description, value, ref):
        for i in range(total_rows):
            if i < len(ref):
                table.setItem(i, 0, QtWidgets.QTableWidgetItem(variable[i]))
                table.setItem(i, 1, QtWidgets.QTableWidgetItem(Description[i]))

                table.setItem(i, 3, QtWidgets.QTableWidgetItem(ref[i]))

                try:
                    table.setItem(i, 2, QtWidgets.QTableWidgetItem(str(round(value[i],3))))
                except:
                    table.setItem(i, 2, QtWidgets.QTableWidgetItem(str(value[i])))




            else:
                table.setItem(i, 0, QtWidgets.QTableWidgetItem(""))
                table.setItem(i, 1, QtWidgets.QTableWidgetItem(""))
                table.setItem(i, 2, QtWidgets.QTableWidgetItem(""))
                table.setItem(i, 3, QtWidgets.QTableWidgetItem(""))

